#  1. LOGGING / UI (SEGMENT 2: FULL IMPROVEMENT)
# ============================================================
class ChimeraLogger:
    """Forensic-grade, async-safe, cryptographically chained telemetry system."""

    COLORS = {
        "DBG": "\033[90m", "INF": "\033[36m", "OK": "\033[32m",
        "WRN": "\033[33m", "ERR": "\033[31m", "HIT": "\033[95m",
        "SYS": "\033[94m", "RST": "\033[0m"
    }
    LOG_LEVELS = {10: "DBG", 20: "INF", 25: "OK", 30: "WRN", 40: "ERR", 50: "HIT", 60: "SYS"}

    def __init__(self, path: Path, verbose=False, json_output=False):
        self.path = path
        self.verbose = verbose
        self.json_output = json_output
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self._lock = asyncio.Lock()
        self._queue = asyncio.Queue()
        self._chain_key = hashlib.pbkdf2_hmac(
            'sha256', OP_KEY, b'chimera_log_chain_salt', CRYPTO_ITERATIONS)
        self._last_hash = hashlib.sha256(self._chain_key).hexdigest()
        self._file_index = 0
        self._fh = self._open_new_log()
        self._writer_task = None

    def _open_new_log(self):
        seed = random.choice(USER_AGENT_POOL).encode()
        suffix = hashlib.md5(seed + secrets.token_bytes(8)).hexdigest()[:8]
        evasive_path = self.path.with_name(f".{suffix}.tmp")
        try:
            fh = open(evasive_path, "a", buffering=1)
            if sys.platform == "linux":
                try:
                    subprocess.run(['chattr', '+i', str(evasive_path)],
                                   timeout=2, stderr=subprocess.DEVNULL)
                except Exception:
                    pass
            return fh
        except Exception:
            return open(self.path, "a", buffering=1)

    async def start(self):
        loop = asyncio.get_event_loop()
        self._writer_task = loop.create_task(self._async_writer_loop())

    async def stop(self):
        await self._queue.put(None)
        if self._writer_task:
            await self._writer_task
        self._fh.close()

    async def _async_writer_loop(self):
        while True:
            item = await self._queue.get()
            if item is None:
                break
            line_str, json_str, raw_data = item
            chain_hash = hashlib.sha256(f"{self._last_hash}{raw_data}".encode()).hexdigest()
            self._last_hash = chain_hash
            async with self._lock:
                try:
                    if self.json_output:
                        self._fh.write(f"{json_str}\n")
                    else:
                        self._fh.write(f"{line_str} [chain:{chain_hash[:8]}]\n")
                except (IOError, OSError):
                    self._fh.close()
                    self._fh = self._open_new_log()

    def _format_log(self, lvl: str, msg: str, context: dict = None):
        ts = datetime.now(timezone.utc).strftime("%H:%M:%S.%f")[:-3]
        c = self.COLORS.get(lvl, "")
        r = self.COLORS["RST"]
        raw_data = f"[{ts}] [{lvl}] {msg}"
        if context:
            raw_data += f" | CTX: {json.dumps(context, separators=(',', ':'))}"
        line_str = f"{c}[{ts}] [{lvl}]{r} {msg}"
        log_obj = {"ts": ts, "level": lvl, "msg": msg, "chain": self._last_hash[:8], "context": context or {}}
        json_str = json.dumps(log_obj, separators=(',', ':'))
        return line_str, json_str, raw_data

    def _log(self, lvl: str, msg: str, context: dict = None):
        if lvl == "DBG" and not self.verbose:
            return
        line_str, json_str, raw_data = self._format_log(lvl, msg, context)
        print(line_str, flush=True)
        try:
            self._queue.put_nowait((line_str, json_str, raw_data))
        except asyncio.QueueFull:
            self._fh.write(f"{raw_data} [SYNC_FALLBACK]\n")

    def dbg(self, m: str, context: dict = None): self._log("DBG", m, context)
    def inf(self, m: str, context: dict = None): self._log("INF", m, context)
    def ok(self, m: str, context: dict = None): self._log("OK", m, context)
    def wrn(self, m: str, context: dict = None): self._log("WRN", m, context)
    def err(self, m: str, context: dict = None): self._log("ERR", m, context)
    def hit(self, m: str, context: dict = None): self._log("HIT", f"⚑ {m}", context)
    def sys(self, m: str, context: dict = None): self._log("SYS", m, context)

    def rotate_log_file(self):
        self._fh.close()
        self._fh = self._open_new_log()
        self.sys("Log file rotated for operational security.")


class ProgressBar:
    """A simple terminal progress bar that works with or without rich."""
    def __init__(self, total: int, desc: str = "", width: int = 40):
        self.total = max(total, 1)
        self.desc = desc
        self.width = width
        self.n = 0
        self.start = time.time()
        self._last_pct = -1
    def update(self, n: int = 1):
        self.n += n
        pct = int(self.n / self.total * 100)
        if pct <= self._last_pct: return
        self._last_pct = pct
        filled = int(self.width * self.n / self.total)
        bar = "█" * filled + "░" * (self.width - filled)
        elapsed = time.time() - self.start
        eta = (elapsed / max(self.n, 1)) * (self.total - self.n) if self.n > 0 else 0
        sys.stderr.write(f"\r  {self.desc} [{bar}] {pct:3d}%  {self.n}/{self.total}  "
                         f"{elapsed:.1f}s/{eta:.1f}s")
        if self.n >= self.total:
            sys.stderr.write(f"\n")
        sys.stderr.flush()
    def __enter__(self): return self
    def __exit__(self, *a): self.update(0)


