#  Forensic-grade, cryptographically sealed, async-safe SQLite matrix.
# ============================================================
class State:
    """Forensic-grade, cryptographically sealed, async-safe SQLite matrix."""
    SCHEMA = """
    PRAGMA journal_mode=WAL;
    PRAGMA synchronous=NORMAL;
    PRAGMA foreign_keys=ON;
    PRAGMA temp_store=MEMORY;

    CREATE TABLE IF NOT EXISTS hosts (
        id TEXT PRIMARY KEY, addr TEXT UNIQUE, hostname TEXT, os_guess TEXT,
        owned INTEGER DEFAULT 0, foothold TEXT, persistent INTEGER DEFAULT 0,
        exfilled INTEGER DEFAULT 0, cleaned INTEGER DEFAULT 0,
        lateral_done INTEGER DEFAULT 0, looted INTEGER DEFAULT 0,
        first_seen TEXT, last_seen TEXT
    );
    CREATE INDEX IF NOT EXISTS idx_hosts_owned ON hosts(owned);
    CREATE INDEX IF NOT EXISTS idx_hosts_addr ON hosts(addr);

    CREATE TABLE IF NOT EXISTS services (
        id TEXT PRIMARY KEY, host_id TEXT, port INTEGER, proto TEXT,
        banner TEXT, server TEXT, tech TEXT, tls INTEGER, title TEXT,
        fp_done INTEGER DEFAULT 0, bf_done INTEGER DEFAULT 0,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );
    CREATE INDEX IF NOT EXISTS idx_services_host ON services(host_id);
    CREATE INDEX IF NOT EXISTS idx_services_tech ON services(tech);

    CREATE TABLE IF NOT EXISTS findings (
        id TEXT PRIMARY KEY, host_id TEXT, service_id TEXT, kind TEXT,
        severity INTEGER, detail TEXT, ts TEXT,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS creds (
        id TEXT PRIMARY KEY, host_id TEXT, proto TEXT, username TEXT,
        secret TEXT, source TEXT, validated INTEGER, ts TEXT,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS sessions (
        id TEXT PRIMARY KEY, host_id TEXT, kind TEXT, established TEXT,
        last_beacon TEXT, status TEXT, meta TEXT,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS plans (
        id TEXT PRIMARY KEY, parent TEXT, intent TEXT, target TEXT,
        status TEXT, result TEXT, attempts INTEGER DEFAULT 0, ts TEXT
    );
    CREATE INDEX IF NOT EXISTS idx_plans_status ON plans(status);

    CREATE TABLE IF NOT EXISTS loot (
        id TEXT PRIMARY KEY, host_id TEXT, kind TEXT, path TEXT,
        bytes INTEGER, sha256 TEXT, exfilled INTEGER DEFAULT 0, ts TEXT,
        enc_key_hash TEXT,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS mesh (
        id TEXT PRIMARY KEY, host_id TEXT, listen TEXT, peers TEXT, status TEXT,
        FOREIGN KEY(host_id) REFERENCES hosts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS notes (
        id INTEGER PRIMARY KEY AUTOINCREMENT, ts TEXT, msg TEXT
    );
    """

    def __init__(self, path: Path):
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)
        self.con = sqlite3.connect(str(self.path), check_same_thread=False, isolation_level=None)
        self.con.executescript(self.SCHEMA)
        self.lock = asyncio.Lock()
        self._enc_key = hashlib.pbkdf2_hmac(
            'sha256', OP_KEY, b'chimera_state_loot_salt', CRYPTO_ITERATIONS)
        self._enc_key_hash = hashlib.sha256(self._enc_key).hexdigest()

    def _encrypt_data(self, plaintext: bytes) -> bytes:
        key = self._enc_key
        return bytes(c ^ key[i % len(key)] for i, c in enumerate(plaintext))

    def _decrypt_data(self, ciphertext: bytes) -> bytes:
        return self._encrypt_data(ciphertext)

    async def q(self, sql: str, args: tuple = ()) -> list:
        async with self.lock:
            loop = asyncio.get_event_loop()
            cur = await loop.run_in_executor(None, lambda: self.con.execute(sql, args))
            return cur.fetchall()

    async def q_exec(self, sql: str, args: tuple = ()):
        async with self.lock:
            loop = asyncio.get_event_loop()
            await loop.run_in_executor(None, lambda: self.con.execute(sql, args))

    async def upsert_host(self, addr: str, hostname: str = "") -> str:
        hid = hashlib.sha1(addr.encode()).hexdigest()[:12]
        now = datetime.now(timezone.utc).isoformat()
        await self.q_exec(
            "INSERT OR IGNORE INTO hosts(id,addr,hostname,first_seen,last_seen) VALUES(?,?,?,?,?)",
            (hid, addr, hostname, now, now))
        await self.q_exec(
            "UPDATE hosts SET last_seen=?, hostname=COALESCE(NULLIF(?,''),hostname) WHERE id=?",
            (now, hostname, hid))
        return hid

    async def get_host_by_addr(self, addr: str) -> Optional[dict]:
        rows = await self.q(
            "SELECT id,addr,hostname,os_guess,owned,foothold,persistent,exfilled,cleaned,lateral_done,looted FROM hosts WHERE addr=?", (addr,))
        if rows:
            r = rows[0]
            return {"id": r[0], "addr": r[1], "hostname": r[2], "os_guess": r[3],
                    "owned": bool(r[4]), "foothold": r[5], "persistent": bool(r[6]),
                    "exfilled": bool(r[7]), "cleaned": bool(r[8]), "lateral_done": bool(r[9]), "looted": bool(r[10])}
        return None

    async def add_service(self, host_id: str, port: int, proto: str, banner: str = "",
                          server: str = "", tech: str = "", tls: int = 0, title: str = "") -> str:
        sid = hashlib.sha1(f"{host_id}:{port}".encode()).hexdigest()[:12]
        await self.q_exec(
            "INSERT OR REPLACE INTO services VALUES(?,?,?,?,?,?,?,?,?,?,?)",
            (sid, host_id, port, proto, banner[:600], server, tech, int(tls), title[:160], 0, 0))
        return sid

    async def update_service_fp(self, sid: str, server: str, tech: str, title: str, tls: int):
        await self.q_exec(
            "UPDATE services SET server=?, tech=?, title=?, tls=?, fp_done=1 WHERE id=?",
            (server, tech, title[:160], int(tls), sid))

    async def add_finding(self, host_id: str, service_id: str, kind: str, severity: int, detail: str) -> str:
        fid = hashlib.sha1(f"{host_id}{kind}{detail}".encode()).hexdigest()[:12]
        await self.q_exec(
            "INSERT OR REPLACE INTO findings VALUES(?,?,?,?,?,?,?)",
            (fid, host_id, service_id, kind, severity, detail[:2000], datetime.now(timezone.utc).isoformat()))
        return fid

    async def add_cred(self, host_id: str, proto: str, user: str, secret: str, source: str, validated: int = 0) -> str:
        cid = hashlib.sha1(f"{host_id}{proto}{user}{secret}".encode()).hexdigest()[:12]
        await self.q_exec(
            "INSERT OR REPLACE INTO creds VALUES(?,?,?,?,?,?,?,?)",
            (cid, host_id, proto, user, secret, source, validated, datetime.now(timezone.utc).isoformat()))
        return cid

    async def open_session(self, host_id: str, kind: str, meta: str = "") -> str:
        sid = uuid.uuid4().hex[:12]
        now = datetime.now(timezone.utc).isoformat()
        await self.q_exec(
            "INSERT INTO sessions VALUES(?,?,?,?,?,?,?)",
            (sid, host_id, kind, now, now, "live", meta))
        await self.q_exec("UPDATE hosts SET owned=1, foothold=? WHERE id=?", (kind, host_id))
        return sid

    async def beacon(self, sid: str):
        await self.q_exec(
            "UPDATE sessions SET last_beacon=? WHERE id=?",
            (datetime.now(timezone.utc).isoformat(), sid))

    async def add_loot(self, host_id: str, kind: str, path: str, data: bytes) -> str:
        sha = hashlib.sha256(data).hexdigest()
        lid = sha[:12]
        enc_data = self._encrypt_data(data)
        await self.q_exec(
            "INSERT OR REPLACE INTO loot VALUES(?,?,?,?,?,?,?,?,?)",
            (lid, host_id, kind, path, len(enc_data), sha, 0, datetime.now(timezone.utc).isoformat(), self._enc_key_hash))
        return lid

    async def queue_plan(self, parent: str, intent: str, target: str) -> str:
        pid = uuid.uuid4().hex[:12]
        await self.q_exec(
            "INSERT INTO plans VALUES(?,?,?,?,?,?,0,?)",
            (pid, parent, intent, target, "queued", "", datetime.now(timezone.utc).isoformat()))
        return pid

    async def next_plan(self) -> Optional[tuple]:
        rows = await self.q(
            "SELECT id,intent,target,attempts FROM plans WHERE status='queued' ORDER BY attempts ASC, ts ASC LIMIT 1")
        return rows[0] if rows else None

    async def finish_plan(self, pid: str, status: str, result: str = ""):
        await self.q_exec("UPDATE plans SET status=?, result=? WHERE id=?", (status, result[:2000], pid))

    async def bump_plan(self, pid: str):
        await self.q_exec("UPDATE plans SET attempts=attempts+1, status='queued' WHERE id=?", (pid,))

    async def hosts_owned(self) -> list:
        return await self.q("SELECT id,addr,foothold,persistent,exfilled,cleaned,lateral_done,looted FROM hosts WHERE owned=1")

    async def all_services(self) -> list:
        return await self.q(
            "SELECT s.host_id,h.addr,s.port,s.proto,s.tech,s.server,s.tls,s.fp_done,s.bf_done "
            "FROM services s JOIN hosts h ON s.host_id=h.id")

    async def creds_for(self, host_id: str, proto: str = None) -> list:
        if proto:
            return await self.q("SELECT username,secret FROM creds WHERE host_id=? AND proto=?", (host_id, proto))
        return await self.q("SELECT proto,username,secret FROM creds WHERE host_id=?", (host_id,))

    async def note(self, msg: str):
        await self.q_exec("INSERT INTO notes(ts,msg) VALUES(?,?)",
                          (datetime.now(timezone.utc).isoformat(), msg))


# ============================================================
#  4. PLANNER / LLM CORTEX (SEGMENT 4: FULL IMPROVEMENT)
#  Dual-pathway Neural Cortex: Deterministic FSM + LLM Inference
# ============================================================
class Planner:
    """CHIMERA's strategic core. Gracefully degrades from LLM inference
    to a zero-trust Finite State Machine (FSM) based on availability."""

    LLM_SCHEMA = textwrap.dedent("""\
    You are CHIMERA-PRIME, an autonomous cyber operations AI. You receive a JSON snapshot of the
    current operation state and must return a JSON action describing the SINGLE next move.

    ALLOWED ACTIONS (STRICT JSON SCHEMA):
      {"action":"recon","target":"<host>"}
      {"action":"scan","target":"<host>"}
      {"action":"fingerprint","target":"<host:port>"}
      {"action":"exploit","module":"<name>","target":"<host:port>"}
      {"action":"bruteforce","proto":"ssh|ftp|http","target":"<host:port>"}
      {"action":"lateral","from":"<host>","to":"<host>"}
      {"action":"persist","target":"<host>"}
      {"action":"loot","target":"<host>"}
      {"action":"exfil","target":"<host>"}
      {"action":"cleanup","target":"<host>"}
      {"action":"done"}

    STRATEGIC PRIORITY:
    1. Recon unowned roots -> Scan unscanned hosts -> Fingerprint unfingerprinted services.
    2. Exploit high-severity candidates -> Bruteforce accessible auth.
    3. Lateral movement to new subnets -> Loot credentials and data.
    4. Persist access -> Exfiltrate loot -> Cleanup logs -> Done.

    REPLY WITH ONLY THE JSON OBJECT. NO PROSE. NO MARKDOWN.
    """)

    def __init__(self, log: ChimeraLogger, model_path: Optional[str] = None):
        self.log = log
        self.llm = None
        self._schema_hash = self._hash_schema()
        if model_path and HAS_LLM:
            try:
                self.log.sys(f"Initializing Neural Cortex with model: {model_path}")
                self.llm = Llama(model_path=model_path, n_ctx=4096, n_gpu_layers=0,
                                 verbose=False, rope_freq_base=10000, seed=42)
                self.log.ok("Neural Cortex online. LLM inference active.")
            except Exception as e:
                self.log.err(f"Neural Cortex load failed -> engaging FSM fallback ({e})")
                self.llm = None
        else:
            self.log.sys("No model provided -> rule-based FSM core active")

    def _hash_schema(self) -> str:
        return hashlib.pbkdf2_hmac(
            'sha256', self.LLM_SCHEMA.encode(), b'chimera_planner_schema_salt', CRYPTO_ITERATIONS).hex()[:16]

    def decide(self, state_snapshot: dict) -> dict:
        if self.llm:
            action = self._llm_infer(state_snapshot)
            if action:
                return action
            self.log.wrn("LLM inference failed/invalid -> falling back to FSM")
        return self._fsm_evaluate(state_snapshot)

    def _llm_infer(self, state_snapshot: dict) -> Optional[dict]:
        try:
            state_json = json.dumps(state_snapshot, separators=(',', ':'))[:3500]
            prompt = f"<|im_start|>system\n{self.LLM_SCHEMA}\n<|im_end|>\n<|im_start|>user\n{state_json}\n<|im_end|>\n<|im_start|>assistant\n"
            output = self.llm(prompt, max_tokens=150, temperature=0.2, stop=["<|im_end|>", "\n\n", "}"])
            raw_text = output["choices"][0]["text"].strip()
            if not raw_text.endswith("}"):
                raw_text += "}"
            match = re.search(r"\{.*\}", raw_text, re.S)
            if not match:
                self.log.err(f"LLM output missing JSON structure: {raw_text}")
                return None
            action = json.loads(match.group(0))
            if not self._validate_action(action):
                self.log.err(f"LLM action violated schema: {action}")
                return None
            self.log.inf(f"Neural Cortex decision: {action.get('action')} -> {action.get('target', action.get('module', ''))}")
            return action
        except json.JSONDecodeError as e:
            self.log.err(f"LLM JSON decode error: {e}")
            return None
        except Exception as e:
            self.log.err(f"LLM inference exception: {e}")
            return None

    def _validate_action(self, action: dict) -> bool:
        if "action" not in action:
            return False
        act = action["action"]
        valid_actions = ["recon", "scan", "fingerprint", "exploit", "bruteforce",
                         "lateral", "persist", "loot", "exfil", "cleanup", "done"]
        if act not in valid_actions:
            return False
        if act in ["recon", "scan", "fingerprint", "persist", "loot", "exfil", "cleanup"]:
            if "target" not in action:
                return False
        elif act == "exploit":
            if "module" not in action or "target" not in action:
                return False
        elif act == "bruteforce":
            if "proto" not in action or "target" not in action:
                return False
            if action["proto"] not in ["ssh", "ftp", "http", "database"]:
                return False
        elif act == "lateral":
            if "from" not in action:
                return False
        return True

    def _fsm_evaluate(self, s: dict) -> dict:
        hosts = s.get("hosts", [])
        services = s.get("services", [])
        owned = s.get("owned", [])
        if not s.get("recon_done"):
            return {"action": "recon", "target": s["root"]}
        for h in hosts:
            if not h.get("scanned"):
                return {"action": "scan", "target": h["addr"]}
        for svc in services:
            if not svc.get("fp_done"):
                return {"action": "fingerprint", "target": f"{svc['addr']}:{svc['port']}"}
        for svc in services:
            for mod in svc.get("candidates", []):
                return {"action": "exploit", "module": mod, "target": f"{svc['addr']}:{svc['port']}"}
        for svc in services:
            if svc["proto"] in ("ssh", "ftp", "http", "database") and not svc.get("bf_done"):
                return {"action": "bruteforce", "proto": svc["proto"], "target": f"{svc['addr']}:{svc['port']}"}
        for h in owned:
            if not h.get("looted"):
                return {"action": "loot", "target": h["addr"]}
            if not h.get("persistent"):
                return {"action": "persist", "target": h["addr"]}
            if not h.get("lateral_done"):
                target_ip = self._find_lateral_target(h["addr"], hosts)
                return {"action": "lateral", "from": h["addr"], "to": target_ip if target_ip else h["addr"]}
            if not h.get("exfilled"):
                return {"action": "exfil", "target": h["addr"]}
            if not h.get("cleaned"):
                return {"action": "cleanup", "target": h["addr"]}
        return {"action": "done"}

    def _find_lateral_target(self, source_addr: str, hosts: list) -> str:
        try:
            src_net = ipaddress.ip_network(f"{source_addr}/24", strict=False)
            for h in hosts:
                if not h.get("owned") and ipaddress.ip_address(h["addr"]) in src_net:
                    return h["addr"]
        except Exception:
            pass
        return ""


