#  5. RECON ENGINE (SEGMENT 5: FULL IMPROVEMENT)
#  Spectral Asynchronous Reconnaissance Hydra
# ============================================================
class Recon:
    """Asynchronous reconnaissance engine. Distributes queries across multiple
    DNS resolvers, rotates User-Agents, and performs high-speed spectral fingerprinting."""

    def __init__(self, log: ChimeraLogger, state: State):
        self.log = log
        self.state = state
        self.sem_net = asyncio.Semaphore(MAX_CONCURRENT_RECON)
        self.dns_resolvers = []
        for r_ip in DNS_RESOLVERS:
            res = get_safe_resolver()
            res.nameservers = [r_ip]
            res.lifetime = BASE_TIMEOUT + 1.0
            res.timeout = BASE_TIMEOUT
            self.dns_resolvers.append(res)

    def _get_random_ua(self) -> str:
        return random.choice(USER_AGENT_POOL)

    def _get_resolver(self) -> dns.asyncresolver.Resolver:
        return random.choice(self.dns_resolvers)

    async def resolve(self, name: str, qtype: str = "A") -> list[str]:
        async with self.sem_net:
            resolver = self._get_resolver()
            try:
                ans = await resolver.resolve(name, qtype)
                return [r.to_text() for r in ans]
            except Exception:
                return []

    async def reverse_dns(self, ip: str) -> str:
        try:
            rev_name = dns.reversename.from_address(ip)
            ans = await self._get_resolver().resolve(rev_name, "PTR")
            return str(ans[0]).rstrip(".")
        except Exception:
            return ""

    async def subdomain_sweep(self, root: str) -> list[tuple[str, str]]:
        self.log.inf(f"Initiating spectral subdomain sweep — {root}")
        live = []
        async def check_word(word: str):
            host = f"{word}.{root}"
            ips = await self.resolve(host)
            if ips:
                ip = ips[0]
                ptr = await self.reverse_dns(ip)
                if ptr and root not in ptr and "parking" in ptr.lower():
                    return
                live.append((host, ip))
                await self.state.upsert_host(ip, host)
                self.log.ok(f"  [Sweep] {host} -> {ip}")
        tasks = [check_word(w) for w in SUBS]
        await asyncio.gather(*tasks)
        root_ips = await self.resolve(root)
        if root_ips:
            live.append((root, root_ips[0]))
            await self.state.upsert_host(root_ips[0], root)
        self.log.inf(f"Sweep complete. {len(live)} live hosts resolved for {root}")
        return live

    async def port_scan(self, host: str, ports: list[int] = None) -> list[int]:
        target_ports = ports or DEFAULT_PORTS
        self.log.inf(f"Scanning {host} — {len(target_ports)} ports")
        open_ports = []
        async def probe(port: int):
            async with self.sem_net:
                try:
                    fut = asyncio.open_connection(host, port)
                    r, w = await asyncio.wait_for(fut, timeout=BASE_TIMEOUT)
                    w.close()
                    try: await w.wait_closed()
                    except: pass
                    open_ports.append(port)
                except (asyncio.TimeoutError, ConnectionRefusedError, OSError):
                    pass
                except Exception:
                    pass
        chunk_size = MAX_CONCURRENT_RECON
        for i in range(0, len(target_ports), chunk_size):
            chunk = target_ports[i:i+chunk_size]
            await asyncio.gather(*(probe(p) for p in chunk))
        return open_ports

    async def banner(self, host: str, port: int) -> str:
        try:
            fut = asyncio.open_connection(host, port)
            r, w = await asyncio.wait_for(fut, timeout=BASE_TIMEOUT)
            try:
                w.write(f"HEAD / HTTP/1.0\r\nHost: {host}\r\nUser-Agent: {self._get_random_ua()}\r\n\r\n".encode())
                await w.drain()
            except Exception:
                pass
            data = b""
            try:
                data = await asyncio.wait_for(r.read(1024), timeout=BASE_TIMEOUT)
            except Exception:
                pass
            w.close()
            return data.decode(errors="ignore")
        except Exception:
            return ""

    async def http_fingerprint(self, host: str, port: int, tls: bool) -> tuple[str, list[str], str]:
        scheme = "https" if tls else "http"
        url = f"{scheme}://{host}:{port}/"
        try:
            timeout = aiohttp.ClientTimeout(total=BASE_TIMEOUT + 4)
            conn = aiohttp.TCPConnector(ssl=False)
            async with aiohttp.ClientSession(connector=conn, timeout=timeout,
                                              headers={"User-Agent": self._get_random_ua()}) as session:
                async with session.get(url, allow_redirects=True) as r:
                    body = await r.text(errors="ignore")
                    headers = dict(r.headers)
        except Exception:
            return ("", [], "")

        blob = "\n".join(f"{k}: {v}" for k, v in headers.items()) + "\n" + body[:20000]
        tech_matches = []
        for category, sigs_dict in TECH_SIGS.items():
            for tech_name, patterns in sigs_dict.items():
                for pattern in patterns:
                    if re.search(pattern, blob, re.I):
                        tech_matches.append(tech_name)
                        break
        server = headers.get("Server", "") or headers.get("server", "")
        title = ""
        m = re.search(r"<title[^>]*>([^<]+)</title>", body, re.I)
        if m: title = m.group(1).strip()[:160]
        return (server, tech_matches, title)


